__kernel void hotspotOpt1(
    __global const float* pIn,
    __global float* tIn,
    __global float* tOut,
    const float stepDivCap,
    const int nx,
    const int ny,
    const int nz,
    const float ce,
    const float cw,
    const float cn,
    const float cs,
    const float ct,
    const float cb,
    const float cc,
    const float amb_temp)
{
    int x = get_global_id(0);
    int y = get_global_id(1);

    if (x >= nx || y >= ny) {
        return;
    }

    int c = x + y * nx;
    int w = (x == 0) ? c : c - 1;
    int e = (x == nx - 1) ? c : c + 1;
    int n = (y == 0) ? c : c - nx;
    int s = (y == ny - 1) ? c : c + nx;

    for (int z = 0; z < nz; z++) {
        int base = z * nx * ny;
        int idx_c = base + c;
        int idx_w = base + w;
        int idx_e = base + e;
        int idx_n = base + n;
        int idx_s = base + s;
        int idx_b = (z == 0) ? idx_c : idx_c - nx * ny;
        int idx_t = (z == nz - 1) ? idx_c : idx_c + nx * ny;

        float val = cc * tIn[idx_c] + cw * tIn[idx_w] + ce * tIn[idx_e]
                    + cs * tIn[idx_s] + cn * tIn[idx_n] + cb * tIn[idx_b] + ct * tIn[idx_t]
                    + stepDivCap * pIn[idx_c] + ct * amb_temp;

        tOut[idx_c] = val;
    }
}
